import '../lib/packet_decoder.dart';
import '../lib/temperature.dart';

void check(bool condition, String message) {
  if (!condition) throw StateError(message);
}

void main() {
  final negative = decodeSensorFrame([0xda, 0xfd, 0x01]);
  check(negative.rawTemperature == -550, 'negative raw reading remains negative');
  check(temperatureCelsius(negative) == -5.5, 'negative Celsius conversion');

  final unavailable = decodeSensorFrame([0x00, 0x80, 0x01]);
  check(
    temperatureCelsius(unavailable) == null,
    'unavailable sample is not converted into a temperature',
  );
}
